dark.customCSS:
/* --- ENTROPY: INDUSTRIAL CONTAINMENT UI --- */

/* Industrial Typography */
body, .prose {
	font-family: 'JetBrains Mono', monospace !important;
	text-transform: lowercase;
}

/* Chromatic Aberration Headers */
.prose h1, .prose h2, .prose h3 {
	color: #ffff00 !important;
	text-transform: uppercase !important;
	letter-spacing: 4px;
	text-shadow: 2px 0px 0px rgba(255,0,0,0.8), -2px 0px 0px rgba(0,0,255,0.8) !important;
}

/* Hazard Containment Panels */
.prose, .bg-gray-850, #sidebar {
	border: 1px solid #ffff00 !important;
	border-top: 8px solid !important;
	border-image: repeating-linear-gradient(45deg, #ffff00, #ffff00 10px, #000 10px, #000 20px) 8 !important;
	background: rgba(5, 5, 0, 0.9) !important;
	border-radius: 0px !important;
}

/* Polygonal Brutalist Inputs */
input, textarea {
	background: #0a0a00 !important;
	border: 1px solid #ffff00 !important;
	border-radius: 0px !important;
	clip-path: polygon(0 0, 95% 0, 100% 20%, 100% 100%, 5% 100%, 0 80%) !important;
	padding-left: 20px !important;
}

/* High-Visibility Phosphor Buttons */
button.bg-blue-500, button.bg-blue-600, .btn-primary {
	background: #ffff00 !important;
	color: #000 !important;
	font-weight: 900 !important;
	border-radius: 0px !important;
	border: none !important;
	text-transform: uppercase;
	outline: 2px solid #ffff00;
	outline-offset: 4px;
	margin: 5px;
}

button.bg-blue-500:hover {
	background: #fff !important;
	outline-offset: 0px;
}

/* Inverted Selection */
::selection {
	background: #ffff00 !important;
	color: #000 !important;
}

/* Custom Scrollbar */
::-webkit-scrollbar {
	width: 12px;
}
::-webkit-scrollbar-thumb {
	background: #ffff00 !important;
	border: 2px solid #000;
}
::-webkit-scrollbar-track {
	background: repeating-linear-gradient(45deg, #121200, #121200 5px, #0a0a00 5px, #0a0a00 10px) !important;
}

dark.canvasScript:
/**
 * Title: Bit-Stream Corruption
 * Description: A chaotic storm of digital artifacts and ASCII bits that scramble near the cursor.
 */

const CONFIG = {
    bitCount: 150,
    color: 'rgba(255, 255, 0, 0.4)',
    glitchColor: 'rgba(255, 255, 255, 0.8)',
    chars: ['0', '1', 'X', '_', '|', '§', 'Δ'],
    fontSize: 12,
    noiseForce: 0.5
};

let canvas, ctx, w, h;
let bits = [];
let mouse = { x: -5000, y: -5000 };

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas; ctx = canvas.getContext('2d');
        resize(e.data.width, e.data.height);
        render();
    } else if (e.data.type === 'resize') {
        resize(e.data.width, e.data.height);
    } else if (e.data.type === 'mousemove') {
        mouse.x = e.data.x; mouse.y = e.data.y;
    }
};

function resize(width, height) {
    w = width; h = height;
    if (canvas) { canvas.width = w; canvas.height = h; }
    bits = [];
    for (let i = 0; i < CONFIG.bitCount; i++) {
        bits.push({
            x: Math.random() * w, y: Math.random() * h,
            char: CONFIG.chars[Math.floor(Math.random() * CONFIG.chars.length)],
            vx: (Math.random() - 0.5) * 4,
            vy: (Math.random() - 0.5) * 4,
            life: Math.random() * 100
        });
    }
}

function render() {
    if (!ctx) return;
    ctx.clearRect(0, 0, w, h);
    ctx.font = `${CONFIG.fontSize}px 'JetBrains Mono', monospace`;

    for (let b of bits) {
        let dx = mouse.x - b.x; let dy = mouse.y - b.y;
        let dist = Math.hypot(dx, dy);

        // Glitch Logic: Scramble positions near mouse
        if (dist < 200) {
            b.x += (Math.random() - 0.5) * 15;
            b.y += (Math.random() - 0.5) * 15;
            ctx.fillStyle = CONFIG.glitchColor;
        } else {
            b.x += b.vx; b.y += b.vy;
            ctx.fillStyle = CONFIG.color;
        }

        // Digital drift
        if (Math.random() > 0.98) b.char = CONFIG.chars[Math.floor(Math.random() * CONFIG.chars.length)];

        // Screen Wrap
        if (b.x < 0) b.x = w; if (b.x > w) b.x = 0;
        if (b.y < 0) b.y = h; if (b.y > h) b.y = 0;

        ctx.fillText(b.char, b.x, b.y);
    }
    requestAnimationFrame(render);
}

